import{_ as i,c as s,o as t,ae as a}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse('{"title":"Notre premier commit","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/git_commit.md","filePath":"drupal-project/installation/git_commit.md"}'),n={name:"drupal-project/installation/git_commit.md"};function o(r,e,l,c,p,d){return t(),s("div",null,e[0]||(e[0]=[a('<h1 id="notre-premier-commit" tabindex="-1">Notre premier commit <a class="header-anchor" href="#notre-premier-commit" aria-label="Permalink to &quot;Notre premier commit&quot;">​</a></h1><p>Nous avons parcouru un bon bout de chemin depuis le début de cette formation ! Récapitulons ce que nous avons accompli :</p><ul><li>Installation de <strong>Drupal</strong> avec <strong>DDEV</strong> et <strong>Composer</strong>.</li><li>Configuration de l&#39;environnement local avec <strong>DDEV</strong>.</li><li>Mise en place des fichiers <strong>settings</strong> et de leur architecture.</li><li>Gestion des données sensibles avec les <strong>variables d&#39;environnement</strong>.</li><li>Export de la <strong>configuration</strong> de Drupal dans des fichiers <em>.yml</em>.</li><li>Création des fichiers <strong>README.md</strong> et <strong>COMMANDS.md</strong>.</li></ul><p>C&#39;est le bon moment pour <strong>versionner</strong> tout ce travail avec <strong>Git</strong> et créer notre premier commit.</p><h2 id="verifier-l-etat-de-notre-configuration" tabindex="-1">Vérifier l&#39;état de notre configuration <a class="header-anchor" href="#verifier-l-etat-de-notre-configuration" aria-label="Permalink to &quot;Vérifier l&#39;état de notre configuration&quot;">​</a></h2><p>Avant de versionner, prenons une bonne habitude : <strong>vérifier que notre configuration Drupal est bien synchronisée</strong>.</p><p>En effet, nous avons fait de nombreuses modifications dans les fichiers <em>settings</em>, activé des modules, et exporté la configuration. Il est important de s&#39;assurer que rien n&#39;a été oublié.</p><p>Pour cela, utilisez la commande suivante :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cst</span></span></code></pre></div><p>Cette commande compare la configuration active (en base de données) avec les fichiers de configuration exportés (dans le dossier <em>config/default</em>).</p><p>Si tout est synchronisé, vous devriez obtenir le message suivant :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[notice] No differences between DB and sync directory.</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">⚠️ Toujours vérifier avant de commiter</p><p>Prendre l&#39;habitude de vérifier la synchronisation de la configuration avant chaque commit est une <strong>bonne pratique essentielle</strong>. Un oubli d&#39;export peut entraîner des incohérences entre votre code et votre base de données, ce qui peut provoquer des erreurs difficiles à diagnostiquer.</p></div><h2 id="versionner-avec-git" tabindex="-1">Versionner avec Git <a class="header-anchor" href="#versionner-avec-git" aria-label="Permalink to &quot;Versionner avec Git&quot;">​</a></h2><p>Maintenant que nous sommes sûrs que tout est en ordre, passons au versionning.</p><h3 id="verifier-l-etat-des-fichiers" tabindex="-1">Vérifier l&#39;état des fichiers <a class="header-anchor" href="#verifier-l-etat-des-fichiers" aria-label="Permalink to &quot;Vérifier l&#39;état des fichiers&quot;">​</a></h3><p>Commençons par observer l&#39;état actuel de notre dépôt :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>Cette commande affiche la liste de tous les fichiers modifiés, ajoutés ou supprimés depuis le dernier commit. Vous devriez voir un bon nombre de fichiers, c&#39;est normal : c&#39;est notre premier commit !</p><p>Prenez le temps de <strong>lire la liste des fichiers</strong>. C&#39;est une étape importante pour vérifier que :</p><ul><li>Les fichiers sensibles (<em>.env</em>, <em>settings.local.php</em>) <strong>ne sont pas</strong> dans la liste grâce au <em>.gitignore</em>.</li><li>Les fichiers de configuration, les <em>settings</em> et les fichiers du projet <strong>sont bien</strong> présents.</li></ul><h3 id="ajouter-les-fichiers-a-l-index" tabindex="-1">Ajouter les fichiers à l&#39;index <a class="header-anchor" href="#ajouter-les-fichiers-a-l-index" aria-label="Permalink to &quot;Ajouter les fichiers à l&#39;index&quot;">​</a></h3><p>Une fois la vérification faite, ajoutez tous les fichiers à l&#39;index de <strong>Git</strong> (zone de préparation) :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">💡Pourquoi <code> .</code> ?</p><p>Le <code>.</code> signifie &quot;tous les fichiers du répertoire courant et de ses sous-dossiers&quot;.</p></div><p>Vous pouvez vérifier ce qui a été ajouté au staging avec :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>Les fichiers devraient maintenant apparaître en <strong>vert</strong>, ce qui signifie qu&#39;ils sont prêts à être commités.</p><h3 id="creer-le-commit" tabindex="-1">Créer le commit <a class="header-anchor" href="#creer-le-commit" aria-label="Permalink to &quot;Créer le commit&quot;">​</a></h3><p>Créez votre premier commit avec un message descriptif :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Initial commit : installation de Drupal avec DDEV&quot;</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">💡 Un bon message de commit</p><p>Un message de commit doit être <strong>court</strong>, <strong>clair</strong> et <strong>décrire ce qui a été fait</strong>. Il doit répondre à la question : <em>&quot;Qu&#39;est-ce que ce commit apporte au projet ?&quot;</em>.</p><p>Évitez les messages vagues comme &quot;fix&quot;, &quot;update&quot; ou &quot;modifications&quot;.</p></div><div class="info custom-block"><p class="custom-block-title">🎉 Félicitation !</p><p>L&#39;installation de notre projet <strong>Drupal</strong> est maintenant terminée et versionnée.</p><p>Il est maintenant temps de découvrir l&#39;interface de <strong>Drupal</strong>.</p></div>',33)]))}const m=i(n,[["render",o]]);export{h as __pageData,m as default};
